import{_ as r,o,c as t,ag as a}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"DroneBridge","description":"https://github.com/DroneBridge/DroneBridge","frontmatter":{"description":"https://github.com/DroneBridge/DroneBridge"},"headers":[],"relativePath":"software-defined-radio/dronebridge.md","filePath":"software-defined-radio/dronebridge.md"}'),i={name:"software-defined-radio/dronebridge.md"};function n(s,e,d,l,g,h){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="dronebridge" tabindex="-1">DroneBridge <a class="header-anchor" href="#dronebridge" aria-label="Permalink to &quot;DroneBridge&quot;">​</a></h1><h2 id="dronebridge-1" tabindex="-1">DroneBridge <a href="#dronebridge-part-2" id="dronebridge-part-2"></a> <a class="header-anchor" href="#dronebridge-1" aria-label="Permalink to &quot;DroneBridge &lt;a href=&quot;#dronebridge-part-2&quot; id=&quot;dronebridge-part-2&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p><img src="https://raw.githubusercontent.com/seeul8er/DroneBridge/nightly/wiki/DroneBridgeLogo_text.png" alt="DroneBridge"></p><p>DroneBridge is a system based on the <a href="https://befinitiv.wordpress.com/wifibroadcast-analog-like-transmission-of-live-video-data/" target="_blank" rel="noreferrer">WifiBroadcast</a> approach. A bidirectional digital radio link between two endpoints is established using standard WiFi hardware and a custom protocol. DroneBridge is optimized for use in UAV applications and is a complete system. It is intended be a real alternative to other similar systems, such as DJI Lightbridge or OcuSync.</p><p>DroneBridge features support for <strong>Raspberry Pi</strong>, <strong>ESP32</strong> on the UAV/ground station side and an <strong>android app</strong>.</p><p>Visit <a href="http://wolfgangchristl.de/not-just-another-drone-project/" target="_blank" rel="noreferrer"><strong>&quot;Not just another drone project&quot;</strong></a> for additional information about the project and its goals</p><h3 id="releases" tabindex="-1">Releases <a class="header-anchor" href="#releases" aria-label="Permalink to &quot;Releases&quot;">​</a></h3><p>Please read the <a href="https://dronebridge.gitbook.io/docs/dronebridge-for-raspberry-pi/getting-started" target="_blank" rel="noreferrer"><strong>getting started guide</strong></a> The v0.7.0 release is recommended.</p><p><strong>Disclaimer: Use at your own risk. Malfunction and sudden signal loss can not be ruled out. Use with caution! Do not fly over people or animals. The user is responsible for:</strong></p><ul><li><strong>Operating the system within legal limits (e. g. frequency, equivalent isotropically radiated power (EIRP) etc.)</strong></li><li><strong>Any harm or damage caused by using the provided software or parts of it.</strong></li></ul><h4 id="v0-7-0-alpha" tabindex="-1">v0.7.0 Alpha <a class="header-anchor" href="#v0-7-0-alpha" aria-label="Permalink to &quot;v0.7.0 Alpha&quot;">​</a></h4><p>Use with caution. RC link has a too high latency. USB connection to DroneBridge for Android is unstable.</p><p><a href="https://wolfgangchristl.de/downloads/DroneBridge_0_7_0_alpha.zip" target="_blank" rel="noreferrer"><strong>DroneBridge Alpha v0.7.0 alpha Image for Raspberry Pi</strong></a></p><p><a href="https://drive.google.com/file/d/1AGMsrWHJvj8HxnZd_8HFgc7dvxMsE9hX/view?usp=sharing" target="_blank" rel="noreferrer"><strong>DroneBridge for Android 2.0.2</strong></a></p><h3 id="one-system-one-digital-radio-link-to-rule-them-all" tabindex="-1">One System. One digital radio link to rule them all. <a class="header-anchor" href="#one-system-one-digital-radio-link-to-rule-them-all" aria-label="Permalink to &quot;One System. One digital radio link to rule them all.&quot;">​</a></h3><p><img src="https://github.com/DroneBridge/DroneBridge/blob/master/wiki/oneforall.jpg" alt="DroneBridge concept"></p><ul><li><strong>300 m - 14+ km range</strong>* (500 m - 2 km with standard hardware)</li><li><strong>1080p video</strong></li><li><strong>110ms glass to glass latency</strong> (using android app)</li><li><strong>Cheap</strong>: starting at 80€ for hardware</li><li><strong>12 channel RC</strong></li><li><strong>MAVLink support</strong> - LTM telemetry deprecated. Use with mwptools, QGroundControl, Mission Planner etc.</li><li><strong>iNAV</strong> &amp; <strong>MAVLink</strong> based flight controller support</li><li><strong>Bidirectional</strong></li><li>Fully integrated <strong>app for Android</strong></li><li><strong>OSD</strong></li><li><strong>Modular - Write your own powerful plugins</strong></li></ul><p>*Range strongly depends on your setup, environment and legal framework.</p><h3 id="dronebridge-for-android" tabindex="-1">DroneBridge for Android <a class="header-anchor" href="#dronebridge-for-android" aria-label="Permalink to &quot;DroneBridge for Android&quot;">​</a></h3><p><img src="https://raw.githubusercontent.com/seeul8er/DroneBridge/master/wiki/dp_app-map-2017-10-29-kleiner.png" alt="DroneBridge for Android app interface"></p><ul><li>Easy to use UI &amp; end point of the whole DroneBridge system</li><li>Low latency video decoding</li><li>Change settings, calibrate the RC, view telemetry</li></ul><p><a href="https://dronebridge.gitbook.io/docs/dronebridge-for-android/dronebridge-for-android" target="_blank" rel="noreferrer"><strong>Learn more about the app</strong></a></p><h3 id="exemplary-hardware-setup" tabindex="-1">Exemplary hardware setup <a class="header-anchor" href="#exemplary-hardware-setup" aria-label="Permalink to &quot;Exemplary hardware setup&quot;">​</a></h3><p>DroneBridge is available for the Raspberry Pi &amp; ESP32 (no video, telemetry only - WiFi based) By compiling the libraries on your Linux computer any device can become an AIR or GND unit. This means DroneBridge is not restricted to the Raspberry Pi. However many single board computers do not offer the same kind of stability and hardware/software support as the Raspberry Pi (camera, H.264 en-/decoding etc.).</p><h4 id="raspberry-pi-linux-long-range-setup" tabindex="-1">Raspberry Pi/Linux (Long Range Setup) <a class="header-anchor" href="#raspberry-pi-linux-long-range-setup" aria-label="Permalink to &quot;Raspberry Pi/Linux (Long Range Setup)&quot;">​</a></h4><p><img src="https://raw.githubusercontent.com/seeul8er/DroneBridge/master/wiki/longrange_setup.png" alt="DroneBridge long range hardware setup"></p><h4 id="dronebridge-for-esp32" tabindex="-1">DroneBridge for ESP32 <a class="header-anchor" href="#dronebridge-for-esp32" aria-label="Permalink to &quot;DroneBridge for ESP32&quot;">​</a></h4><p>For further information have a look at the <a href="https://github.com/DroneBridge/ESP32" target="_blank" rel="noreferrer">DB for ESP32 main page</a> <img src="https://raw.githubusercontent.com/seeul8er/DroneBridge/master/wiki/db_ESP32_setup.png" alt="DroneBridge for ESP32 hardware setup"></p><h3 id="dronebridge-modules" tabindex="-1">DroneBridge Modules <a class="header-anchor" href="#dronebridge-modules" aria-label="Permalink to &quot;DroneBridge Modules&quot;">​</a></h3><p>DroneBridge is highly modularized to provide flexebility and make development easy. There is a common library for Python 3 and C/C++ that handles everything involving the DroneBridge raw protocol. It configures the sockets, inits the protocol and provides methods for easy transmission. Instead of the Android app any other GCS can be used.</p><p><a href="https://dronebridge.gitbook.io/docs/developer-guide/dronebridge-lib-example-usage" target="_blank" rel="noreferrer">Read more in the Wiki</a></p><h3 id="system-architecture" tabindex="-1">System Architecture <a class="header-anchor" href="#system-architecture" aria-label="Permalink to &quot;System Architecture&quot;">​</a></h3><p><a href="https://dronebridge.gitbook.io/docs/developer-guide/system-architecture" target="_blank" rel="noreferrer">Read more in the wiki</a></p><h3 id="coming-up" tabindex="-1">Coming Up: <a class="header-anchor" href="#coming-up" aria-label="Permalink to &quot;Coming Up:&quot;">​</a></h3><ul><li>More documentation</li><li>Add MavLink and MSP waypoint missions editor to Android App</li><li>DroneBridge Cockpit: A client/OS for x86 systems to monitor and control your UAV</li><li>See <a href="https://dronebridge.gitbook.io/docs/dronebridge-for-raspberry-pi/milestones" target="_blank" rel="noreferrer"><strong>milestones</strong></a></li></ul><h3 id="you-are-a-developer" tabindex="-1">You are a developer? <a class="header-anchor" href="#you-are-a-developer" aria-label="Permalink to &quot;You are a developer?&quot;">​</a></h3><p>Check out the <a href="https://dronebridge.gitbook.io/docs/" target="_blank" rel="noreferrer"><strong>wiki</strong></a> Check out the <a href="https://dronebridge.gitbook.io/docs/dronebridge-for-raspberry-pi/milestones" target="_blank" rel="noreferrer"><strong>milestones</strong></a> and suggest new ones! Join the <a href="https://gitter.im/DroneBridge/Lobby?utm_source=share-link&amp;utm_medium=link&amp;utm_campaign=share-link" target="_blank" rel="noreferrer"><strong>Gitter room</strong></a> and discuss issues, ask questions or give feedback</p><p>There is a nightly branch with the most up to date code! It is not guaranteed that the code in that branch is working or even compiling!</p><p><strong>Feel free to ask questions &amp; contribute</strong></p><h3 id="licenses" tabindex="-1">Licenses <a class="header-anchor" href="#licenses" aria-label="Permalink to &quot;Licenses&quot;">​</a></h3><ul><li>All of the code (especially DroneBridge modules &amp; lib_dbcommon - C or Python) is under the Apache 2 license if not specified otherwise</li><li>WifiBroadcast legacy code (video, OSD, .profile, hello_video) is licensed as specified or under the GPL v2 license</li><li>All Kernel drivers/patches are under GPL v2 license</li></ul>',41)])])}const c=r(i,[["render",n]]);export{u as __pageData,c as default};
